#!/usr/bin/env node
// Fit the empirical accuracy->Elo model from scripts/data/elo-corpus.jsonl
// (generated by scripts/gen-elo-corpus.mjs).
//
// Model shape (simple + monotone + CALIBRATED per band):
//   eloAcc(acc)   inverse-calibrated curve: PAV-monotonized band->mean(accuracy)
//                 over the ladder, inverted to accuracy->Elo (piecewise-linear).
//   eloAcpl(acpl) same construction on band->mean(log(1+acpl)) (decreasing).
//   est0 = a0 + a1*eloAcc + (1-a1)*eloAcpl      blend slopes SUM TO 1, so the
//                 per-band calibration of the two inverse curves is preserved
//                 (plain OLS instead regresses to the mean: a first attempt
//                 measured +200..+460 bias at low bands and -100..-230 at the
//                 top — exactly the "completely inaccurate" failure mode).
//                 Without acpl (raw perf:estimate / placement): est0 = c0 + eloAcc.
//   est1 = est0 + bShrink*(est0 - 1500)*s(n)    short-game shrink toward center,
//                 s(n) = sqrt(30/clamp(n,6,30)) - 1 (0 for n >= 30), bShrink
//                 bounded to [-0.32, 0] (shrink-only; the OLS magnitude beyond
//                 that is confounded — short corpus games are decisive
//                 high-band games).
//   with oppElo:  est = (est1 - g*oppElo)/(1 - g)
//                 g is fit STRUCTURALLY: pooled within-band regression slope of
//                 est1 on oppElo (trueElo held fixed => no trueElo~oppElo proxy
//                 leakage; the corpus only pairs +/-0/200/400, so a joint OLS
//                 would just learn "you are rated near your opponent").
//   clamp [250, 3000].
//
// Split: deterministic ~20% holdout by gameKey hash (both rows of a game land
// on the same side). Reports per-band bias/MAE, overall MAE per variant, and
// residual std per nMoves bucket per variant (the honest band half-width).
// Writes scripts/data/elo-fit.json consumed by src/main/analysis/estElo.ts
// (constants) and scripts/test-est-elo.mjs (golden bounds).
//
// Usage: node scripts/fit-elo-model.mjs [--corpus scripts/data/elo-corpus.jsonl]
//                                       [--out scripts/data/elo-fit.json]
// (Path flags only; the default invocation is unchanged. The judge-config refit
// uses --corpus scripts/data/judge-elo-corpus.jsonl --out scripts/data/judge-elo-fit.json.)

import { readFileSync, writeFileSync, mkdirSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'

const argv = process.argv.slice(2)
function flag(name, def) {
  const i = argv.indexOf(`--${name}`)
  return i >= 0 && argv[i + 1] !== undefined ? argv[i + 1] : def
}
const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..')
const CORPUS = path.resolve(repoRoot, flag('corpus', 'scripts/data/elo-corpus.jsonl'))
const OUT = path.resolve(repoRoot, flag('out', 'scripts/data/elo-fit.json'))

const ELO_FLOOR = 250
const ELO_CEIL = 3000
const SHRINK_CENTER = 1500
const SHRINK_FULL_MOVES = 30
const SHRINK_MIN_MOVES = 6

// ---- Load + split -------------------------------------------------------------------

/** Deterministic string hash (FNV-1a 32-bit). Mirrored in test-est-elo.mjs. */
function hashKey(s) {
  let h = 0x811c9dc5
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i)
    h = Math.imul(h, 0x01000193)
  }
  return h >>> 0
}
const isHoldout = (gameKey) => hashKey(gameKey) % 5 === 0

const rows = readFileSync(CORPUS, 'utf8')
  .split('\n')
  .filter(Boolean)
  .map((l) => JSON.parse(l))
  .filter((r) => Number.isFinite(r.accuracy) && r.nMoves >= 4)

const train = rows.filter((r) => !isHoldout(r.gameKey))
const hold = rows.filter((r) => isHoldout(r.gameKey))
if (train.length < 40) {
  console.error(`corpus too small to fit (${train.length} train rows)`)
  process.exit(1)
}

// ---- 1) Inverse-calibrated curves ------------------------------------------------------
// Band -> mean(feature), PAV-monotonized ALONG THE LADDER, then inverted to
// feature -> Elo. Unlike isotonic E[Elo|feature] bins, this stays per-band
// unbiased (calibration): a band-X game maps back to ~X on average.

function calibrationKnots(data, featOf, increasing) {
  const bands = [...new Set(data.map((r) => r.trueElo))].sort((a, b) => a - b)
  const pts = bands.map((band) => {
    const rs = data.filter((r) => r.trueElo === band)
    const v = rs.reduce((a, r) => a + featOf(r), 0) / rs.length
    return { elo: band, v: increasing ? v : -v, w: rs.length }
  })
  // PAV: enforce nondecreasing v along ascending band order.
  const pooled = []
  for (const p of pts) {
    let cur = { ...p, eloW: p.elo * p.w }
    while (pooled.length > 0 && pooled[pooled.length - 1].v >= cur.v) {
      const prev = pooled.pop()
      const w = prev.w + cur.w
      cur = { v: (prev.v * prev.w + cur.v * cur.w) / w, w, eloW: prev.eloW + cur.eloW }
    }
    pooled.push(cur)
  }
  return pooled.map((p) => ({
    feat: Math.round((increasing ? p.v : -p.v) * 1000) / 1000,
    elo: Math.round(p.eloW / p.w)
  }))
}

/** Piecewise-linear feature -> Elo (knots sorted by feat asc or desc), clamped ends. */
function knotElo(knots, v) {
  const asc = knots.length < 2 || knots[1].feat >= knots[0].feat
  const ks = asc ? knots : [...knots].reverse()
  if (v <= ks[0].feat) return ks[0].elo
  const last = ks[ks.length - 1]
  if (v >= last.feat) return last.elo
  for (let i = 1; i < ks.length; i++) {
    if (v <= ks[i].feat) {
      const lo = ks[i - 1]
      const hi = ks[i]
      const t = (v - lo.feat) / (hi.feat - lo.feat)
      return lo.elo + t * (hi.elo - lo.elo)
    }
  }
  return last.elo
}

const accKnots = calibrationKnots(train, (r) => r.accuracy, true)
const acplKnots = calibrationKnots(train, (r) => Math.log(1 + r.acpl), false)

const eloAcc = (acc) => knotElo(accKnots, acc)
const eloAcpl = (acpl) => knotElo(acplKnots, Math.log(1 + acpl))

// ---- 2) Blend (slopes sum to 1) + acc-only calibration ----------------------------------

// est0 = a0 + a1*eloAcc + (1-a1)*eloAcpl: regress (y - eloAcpl) on
// (eloAcc - eloAcpl) with intercept; a1 clamped to [0, 1].
let a0 = 0
let a1 = 0.5
{
  let sx = 0
  let sy = 0
  let sxx = 0
  let sxy = 0
  const n = train.length
  for (const r of train) {
    const x = eloAcc(r.accuracy) - eloAcpl(r.acpl)
    const y = r.trueElo - eloAcpl(r.acpl)
    sx += x
    sy += y
    sxx += x * x
    sxy += x * y
  }
  const denom = sxx - (sx * sx) / n
  a1 = denom > 0 ? (sxy - (sx * sy) / n) / denom : 0.5
  // Floor at 0.1: unconstrained OLS clamps to a1=0 (eloAcc/eloAcpl are ~0.9
  // correlated and ACPL is the stronger single signal — a1 grid: 0 -> holdout
  // MAE 320.0, 0.1 -> 324.6, 0.3 -> 344.6). Keeping a small accuracy weight
  // costs ~4.6 MAE but keeps the estimate robust to ACPL quirks and genuinely
  // responsive to its headline accuracy input.
  a1 = Math.max(0.1, Math.min(1, a1))
  a0 = sy / n - a1 * (sx / n)
}
// Acc-only variant (no acpl available): est0 = c0 + eloAcc.
const c0 =
  train.reduce((a, r) => a + (r.trueElo - eloAcc(r.accuracy)), 0) / train.length

function est0Of(r) {
  if (r.acpl == null) return c0 + eloAcc(r.accuracy)
  return a0 + a1 * eloAcc(r.accuracy) + (1 - a1) * eloAcpl(r.acpl)
}

// ---- 3) Short-game shrink (1-param, bounded) ---------------------------------------------

const shrinkS = (n) =>
  Math.sqrt(SHRINK_FULL_MOVES / Math.max(SHRINK_MIN_MOVES, Math.min(SHRINK_FULL_MOVES, n))) - 1

let bShrink = 0
{
  let sxy = 0
  let sxx = 0
  for (const r of train) {
    const x = (est0Of(r) - SHRINK_CENTER) * shrinkS(r.nMoves)
    const y = r.trueElo - est0Of(r)
    sxy += x * y
    sxx += x * x
  }
  const raw = sxx > 0 ? sxy / sxx : 0
  bShrink = Math.max(-0.32, Math.min(0, raw))
  if (bShrink !== raw) console.log(`shrink clamp: bShrink ${raw.toFixed(4)} -> ${bShrink.toFixed(4)}`)
}

const est1Of = (r) => est0Of(r) + bShrink * (est0Of(r) - SHRINK_CENTER) * shrinkS(r.nMoves)

// ---- 4) Structural opponent slope g ------------------------------------------------------

let g = 0
{
  const byBand = new Map()
  for (const r of train) {
    if (!byBand.has(r.trueElo)) byBand.set(r.trueElo, [])
    byBand.get(r.trueElo).push(r)
  }
  let sxy = 0
  let sxx = 0
  for (const rs of byBand.values()) {
    if (rs.length < 3) continue
    const mO = rs.reduce((a, r) => a + r.oppElo, 0) / rs.length
    const mE = rs.reduce((a, r) => a + est1Of(r), 0) / rs.length
    for (const r of rs) {
      const dO = r.oppElo - mO
      sxy += dO * (est1Of(r) - mE)
      sxx += dO * dO
    }
  }
  g = sxx > 0 ? sxy / sxx : 0
  // Keep the inversion sane (measured g is expected small and negative).
  g = Math.max(-0.6, Math.min(0.6, g))
}

// ---- Predictions --------------------------------------------------------------------------

function predict(r, { useOpp = true } = {}) {
  let est = est1Of(r)
  if (useOpp && r.oppElo != null && g !== 0) est = (est - g * r.oppElo) / (1 - g)
  return Math.max(ELO_FLOOR, Math.min(ELO_CEIL, est))
}

const mae = (data, opts) =>
  data.reduce((a, r) => a + Math.abs(predict(r, opts) - r.trueElo), 0) / data.length

// ---- Reports --------------------------------------------------------------------------------

console.log(`corpus: ${rows.length} rows (${train.length} train / ${hold.length} holdout)`)
console.log('\naccuracy calibration knots (accuracy -> Elo):')
console.log('  ' + accKnots.map((k) => `${k.feat}->${k.elo}`).join('  '))
console.log('acpl calibration knots (log(1+acpl) -> Elo):')
console.log('  ' + acplKnots.map((k) => `${k.feat}->${k.elo}`).join('  '))
console.log(
  `\ncoefficients: a0=${a0.toFixed(1)}  a1(acc weight)=${a1.toFixed(4)}  c0(acc-only)=${c0.toFixed(1)}  ` +
    `bShrink=${bShrink.toFixed(4)}  g(opp)=${g.toFixed(4)}`
)

const variants = [
  ['no opp (estimateElo) ', { useOpp: false }],
  ['with opp (Ex+oppElo) ', { useOpp: true }]
]
console.log('\nvariant                 train MAE   holdout MAE')
const maeReport = {}
for (const [name, opts] of variants) {
  const t = mae(train, opts)
  const h = hold.length ? mae(hold, opts) : NaN
  maeReport[name.trim()] = { train: Math.round(t * 10) / 10, holdout: Math.round(h * 10) / 10 }
  console.log(`${name}    ${t.toFixed(1).padStart(7)}   ${h.toFixed(1).padStart(9)}`)
}
{
  const t = mae(train.map((r) => ({ ...r, acpl: null })), { useOpp: false })
  const h = hold.length ? mae(hold.map((r) => ({ ...r, acpl: null })), { useOpp: false }) : NaN
  maeReport['acc only (no acpl)'] = { train: Math.round(t * 10) / 10, holdout: Math.round(h * 10) / 10 }
  console.log(`acc only (no acpl)        ${t.toFixed(1).padStart(5)}   ${h.toFixed(1).padStart(9)}`)
}

console.log('\nper-band residuals (with-opp model):')
console.log('band   nTr  biasTr   maeTr   nHo  biasHo   maeHo')
const bands = [...new Set(rows.map((r) => r.trueElo))].sort((a, b) => a - b)
const perBand = []
for (const band of bands) {
  const tr = train.filter((r) => r.trueElo === band)
  const ho = hold.filter((r) => r.trueElo === band)
  const resid = (rs) => rs.map((r) => predict(r) - r.trueElo)
  const mean = (xs) => (xs.length ? xs.reduce((a, b) => a + b, 0) / xs.length : NaN)
  const rTr = resid(tr)
  const rHo = resid(ho)
  const row = {
    band,
    nTrain: tr.length,
    biasTrain: Math.round(mean(rTr)),
    maeTrain: Math.round(mean(rTr.map(Math.abs))),
    nHold: ho.length,
    biasHold: ho.length ? Math.round(mean(rHo)) : null,
    maeHold: ho.length ? Math.round(mean(rHo.map(Math.abs))) : null
  }
  perBand.push(row)
  console.log(
    `${String(band).padEnd(6)} ${String(row.nTrain).padEnd(4)} ${String(row.biasTrain).padStart(6)} ` +
      `${String(row.maeTrain).padStart(7)}   ${String(row.nHold).padEnd(4)} ` +
      `${String(row.biasHold ?? '-').padStart(6)} ${String(row.maeHold ?? '-').padStart(7)}`
  )
}

// Residual std per nMoves bucket (ALL rows) -> honest band half-widths, per variant.
const buckets = [
  { label: '<15', lo: 0, hi: 15, mid: 10 },
  { label: '15-24', lo: 15, hi: 25, mid: 20 },
  { label: '25-39', lo: 25, hi: 40, mid: 32 },
  { label: '>=40', lo: 40, hi: Infinity, mid: 48 }
]
function stdBuckets(useOpp, dropAcpl = false) {
  return buckets.map((b) => {
    const rs = rows.filter((r) => r.nMoves >= b.lo && r.nMoves < b.hi)
    const resid = rs.map(
      (r) => predict(dropAcpl ? { ...r, acpl: null } : r, { useOpp }) - r.trueElo
    )
    const m = resid.reduce((a, x) => a + x, 0) / Math.max(1, resid.length)
    const std = Math.sqrt(
      resid.reduce((a, x) => a + (x - m) * (x - m), 0) / Math.max(1, resid.length)
    )
    return { label: b.label, mid: b.mid, n: rs.length, std: Math.round(std) }
  })
}
const residStd = {
  noOpp: stdBuckets(false),
  withOpp: stdBuckets(true),
  accOnly: stdBuckets(false, true)
}
console.log('\nresidual std by nMoves bucket (all rows) — the band half-width:')
console.log('bucket  n      std(noOpp)  std(withOpp)  std(accOnly)')
for (let i = 0; i < buckets.length; i++) {
  console.log(
    `${buckets[i].label.padEnd(7)} ${String(residStd.noOpp[i].n).padEnd(6)} ` +
      `${String(residStd.noOpp[i].std).padStart(10)}  ${String(residStd.withOpp[i].std).padStart(12)}` +
      `${String(residStd.accOnly[i].std).padStart(14)}`
  )
}

// ---- Persist ---------------------------------------------------------------------------------

mkdirSync(path.dirname(OUT), { recursive: true })
writeFileSync(
  OUT,
  JSON.stringify(
    {
      fitDate: new Date().toISOString().slice(0, 10),
      corpus: path.relative(repoRoot, CORPUS),
      corpusRows: rows.length,
      trainRows: train.length,
      holdoutRows: hold.length,
      analysisDepth: rows[0]?.analysisDepth ?? null,
      accKnots,
      acplKnots,
      coef: {
        a0: Math.round(a0 * 10) / 10,
        a1: Math.round(a1 * 10000) / 10000,
        c0: Math.round(c0 * 10) / 10,
        bShrink: Math.round(bShrink * 10000) / 10000,
        gOpp: Math.round(g * 10000) / 10000
      },
      shrink: { center: SHRINK_CENTER, fullMoves: SHRINK_FULL_MOVES, minMoves: SHRINK_MIN_MOVES },
      clamp: { floor: ELO_FLOOR, ceil: ELO_CEIL },
      mae: maeReport,
      perBand,
      residStd
    },
    null,
    2
  )
)
console.log(`\nwrote ${path.relative(repoRoot, OUT)}`)
